    let zero_tabindex_items = ctx
        .items
        .iter()
        .filter(|item| {
            api.item_attrs(&item.value)
                .get(&HtmlAttr::TabIndex)
                .is_some_and(|value| value == "0")
        })
        .collect::<Vec<_>>();

    prop_assert!(zero_tabindex_items.len() <= 1);

    for item in zero_tabindex_items {
        prop_assert!(!item.disabled);
