        self
    }

    /// Sets [`Self::debounce`].
    #[must_use]
    pub const fn debounce(mut self, value: Duration) -> Self {
        self.debounce = Some(value);
        self
    }

    /// Clears [`Self::debounce`].
    #[must_use]
    pub const fn no_debounce(mut self) -> Self {
        self.debounce = None;
