    }

    /// Sets [`Self::loading`].
    #[must_use]
    pub const fn loading(mut self, value: bool) -> Self {
        self.loading = value;
        self
    }

    /// Sets [`Self::disabled`].
    #[must_use]
    pub const fn disabled(mut self, value: bool) -> Self {
        self.disabled = value;
        self
    }

    /// Sets [`Self::collection_id`].
    #[must_use]
    pub fn collection_id(mut self, value: impl Into<String>) -> Self {
